		function HABILITAR()
{	
	if (Ctrl('c_estado').GetXValue() == "N")
		{ 	 		
	 		CtrlEnabled('CARTAS_ENV', false);
	 		CtrlEnabled('EXA_REC', false);
	 		CtrlEnabled('OFERTAS', false);
	 	  	CtrlEnabled('DESCARTADO',false);

	 		if (Ctrl('main').GetMode() == "SHOW")
		 	{
		 		CtrlEnabled('btnSeleccionar', false);
		 		CtrlEnabled('btnContratar', false);
		 	}
	 	} 
	if (Ctrl('c_estado').GetXValue() == "D")
		{ 	 		
	 		CtrlEnabled('DESCARTADO',false);

	 	} 

	if (Ctrl('c_estado').GetXValue() == "R")
		{ 	 		
		 		CtrlEnabled('CARTAS_ENV', false);
		 		//CtrlEnabled('OFERTAS', false);		 		
	      		CtrlEnabled('DESCARTADO',true);

	 		if (Ctrl('main').GetMode() == "SHOW")
		 	{
		 		CtrlEnabled('btnReclutar', false);
		 		CtrlEnabled('btnContratar', false);		 		

		 	}
	 	}
	if (Ctrl('c_estado').GetXValue() == "S")
		{
	 		CtrlEnabled('DESCARTADO',false);  
	 		if (Ctrl('main').GetMode() == "EDIT")  
		 	{
		 		CtrlEnabled('EXA_REC', false);
				CtrlEnabled('DESCARTADO',false);                            	
		 	}
			if (Ctrl('main').GetMode() == "SHOW")
		 	{

				CtrlEnabled('btnSeleccionar', false);
				CtrlEnabled('btnReclutar', false);

		 	}
	 	}
	if (Ctrl('c_estado').GetXValue() == "C")
		{
		 	CtrlEnabled('DESCARTADO',false);
		 	if (Ctrl('main').GetMode() == "SHOW")
		 	{
			 	CtrlEnabled('btnReclutar', false);
			 	CtrlEnabled('btnContratar', false);
			 	CtrlEnabled('btnSeleccionar', false);

			}
	 		if (Ctrl('main').GetMode() == "EDIT")
		 	{                                      
		 	CtrlEnabled('OFERTAS', false);
		 	CtrlEnabled('CARTAS_ENV', false);
		 	CtrlEnabled('EXA_REC', false);
		 	CtrlEnabled('DESCARTADO',false);                                 	
		 	}	 		
	 	}  
}  

