	{
		PARAM = "<DATOS oi_req=\""+Ctrl('grillo').GetXValue()+"\" />";		
	}
	XMLSearch = nSQL.Get(Ctrl("main").getResource("QRY_REC"), PARAM); 
	pp = new nomadDOM(XMLSearch);
	/*alert("PARAM" + PARAM);       
	alert("XMLSEARCH" + XMLSearch);       
	alert("REC"+ Ctrl('grilla').SelectedRowID());
	alert("PER"+ pp.per);
	alert("POS"+ pp.pos);*/

	if (pp.per==pp.undefined) 
	{
		openNewFlowWait("NucleusRH.Base.Gestion_de_Postulantes.Reportes.LegajoPostulante.flow","proceso","<DATOS oi_postulante=\"" + pp.pos + "\" />",new ObjtectResult(),"L");  
